// Clock Divider - ratio 4
module register_with_enable (
  input clk,
  input reset,
  input enable,
  input [3:0] data_in,
  output reg [3:0] data_out
);

  always @(posedge clk or posedge reset) begin
    if (reset)
      data_out <= 4'b0000;
    else if (enable)
      data_out <= data_in;
  end

endmodule
